-- Name: COLUMN "staff"."has_user_account"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "public"."staff"."has_user_account" IS 'Whether this staff member has login credentials (user account created)';


--
-- Name: COLUMN "staff"."user_account_status"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "public"."staff"."user_account_status" IS 'Status of user account: pending (invited but not accepted), active (can login), suspended (login disabled)';


--
-- Name: COLUMN "staff"."invitation_sent_at"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "public"."staff"."invitation_sent_at" IS 'Timestamp when invitation was sent to staff member';


--
-- Name: COLUMN "staff"."invitation_token"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "public"."staff"."invitation_token" IS 'Secure token for staff invitation link (valid for 24 hours)';


--
-- Name: COLUMN "staff"."invitation_expires_at"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN "public"."staff"."invitation_expires_at" IS 'Expiration time for invitation token (typically 24 hours from sent_at)';


--
-- Name: staff_branch_assignments; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE "public"."staff_branch_assignments" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "organisation_id" "uuid" NOT NULL,
    "branch_id" "uuid" NOT NULL,
    "staff_id" "uuid" NOT NULL,
    "assigned_from" "date" DEFAULT CURRENT_DATE NOT NULL,
    "assigned_to" "date",
    "assignment_type" character varying(20) DEFAULT 'permanent'::character varying,
    "branch_role" character varying(50),
    "is_active" boolean DEFAULT true,
    "is_primary" boolean DEFAULT false,
    "notes" "text",
    "created_by" "uuid",
    "created_at" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "updated_at" timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    "deleted_at" timestamp without time zone,
    CONSTRAINT "staff_branch_assignments_assignment_type_check" CHECK ((("assignment_type")::"text" = ANY ((ARRAY['permanent'::character varying, 'temporary'::character varying, 'rotating'::character varying])::"text"[])))
);


--
-- Name: TABLE "staff_branch_assignments"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE "public"."staff_branch_assignments" IS 'Junction table linking staff to branches';


